class Solution:
    def countNonDecreasingSubarrays(self, nums, k):
        n = len(nums)
        total = 0
        for l in range(n):
            for r in range(l, n):
                cur = nums[l]
                cost = 0
                for i in range(l + 1, r + 1):
                    if nums[i] >= cur:
                        cur = nums[i]
                    else:
                        cost += cur - nums[i]
                if cost <= k:
                    total += 1
        return total

