var countNonDecreasingSubarrays = function(nums, k) {
    const n = nums.length;
    let total = 0;
    for (let l = 0; l < n; l++) {
        let cur = nums[l];
        let cost = 0;
        total += 1;
        for (let r = l + 1; r < n; r++) {
            if (nums[r] >= cur) {
                cur = nums[r];
            } else {
                cost += cur - nums[r];
            }
            if (cost > k) break;
            total += 1;
        }
    }
    return total;
};
